3_real_world_example.code:
const API_CONFIG = {
  url: 'https://api.example.com',
  timeout: 5000
};

Object.freeze(API_CONFIG);

//  Ignored (or throws in Strict Mode)
API_CONFIG.timeout = 1000; 
//  Ignored
API_CONFIG.newProp = true;
//  Ignored
delete API_CONFIG.url;

console.log(API_CONFIG); // Exact same as it was initially.

